create table dirkspzm32.isi_kpi_dashboard (
    sid                     varchar2(2 char) not null enable,
    firma_nr                number(2, 0) not null enable,
    wert_datum              date,
    dashboard_name          varchar2(28 char) not null enable,
    kpi_name                varchar2(50 char) not null enable,
    kpi_sel_param           varchar2(1000 char) not null enable,
    text_dashboard          varchar2(50 char),
    text_kpi_zeile          varchar2(50 char),
    text_kpi_spalte         varchar2(50 char),
    text_kpi                varchar2(50 char) not null enable,
    wert_kpi_aktuell        number(*, 6),
    wert_kpi_letzter        number(*, 6),
    wert_kpi_max_y          number(*, 6),
    wert_kpi_schrittweite_y number(*, 6),
    wert_kpi_max_x          number(*, 6),
    wert_kpi_schrittweite_x number(*, 6),
    wert_intervall_sek      number(6, 0) not null enable,
    wert_intervall_next     date,
    created_date            date not null enable,
    created_login_id        number(*, 0) not null enable,
    last_change_date        date,
    last_change_login_id    number(*, 0),
    schwell_wert_gruen      number(*, 6),
    schwell_wert_gelb       number(*, 6),
    isi_kpi_id              varchar2(32 char) not null enable
);

alter table dirkspzm32.isi_kpi_dashboard
    add constraint pk_isi_dashboard
        primary key ( dashboard_name,
                      kpi_name,
                      firma_nr,
                      sid,
                      isi_kpi_id )
            using index enable;


